('axai_ch01_171', 'The empirical formula of a compound gives the:', 'mcq', '["actual number of atoms in a molecule","simplest whole-number ratio of atoms","mass of one molecule","number of moles in a sample"]', 'simplest whole-number ratio of atoms', 'easy', 1, 'neet', 'The empirical formula is the simplest whole-number ratio of the atoms present.', 'chem', 'ch01', 'ch01t3', 'ch01t3s2'),
('axai_ch01_172', 'The molecular formula is always a whole-number multiple of the:', 'mcq', '["atomic mass","empirical formula","molar volume","mole fraction"]', 'empirical formula', 'easy', 1, 'both', 'Molecular formula = n Г— empirical formula, where n is a whole number.', 'chem', 'ch01', 'ch01t3', 'ch01t3s2'),
('axai_ch01_173', 'The empirical formula of glucose Cв‚†Hв‚Ѓв‚‚Oв‚† is:', 'mcq', '["CHO","CHв‚‚O","Cв‚‚Hв‚„Oв‚‚","CHв‚‚Oв‚ѓ"]', 'CHв‚‚O', 'easy', 2, 'both', 'Dividing Cв‚†Hв‚Ѓв‚‚Oв‚† subscripts by 6 gives CHв‚‚O.', 'chem', 'ch01', 'ch01t3', 'ch01t3s2'),
('axai_ch01_174', 'The empirical formula of benzene Cв‚†Hв‚† is:', 'mcq', '["Cв‚†Hв‚†","CH","CHв‚‚","Cв‚‚Hв‚‚"]', 'CH', 'easy', 2, 'both', 'Dividing Cв‚†Hв‚† subscripts by 6 gives CH.', 'chem', 'ch01', 'ch01t3', 'ch01t3s2'),
('axai_ch01_175', 'If the empirical formula is CHв‚‚ and n = 2, the molecular formula is:', 'mcq', '["CHв‚‚","Cв‚‚Hв‚‚","Cв‚‚Hв‚„","Cв‚ѓHв‚†"]', 'Cв‚‚Hв‚„', 'easy', 2, 'both', 'Molecular formula = 2 Г— CHв‚‚ = Cв‚‚Hв‚„.', 'chem', 'ch01', 'ch01t3', 'ch01t3s2'),
('axai_ch01_176', 'The empirical formula of hydrogen peroxide Hв‚‚Oв‚‚ is:', 'mcq', '["Hв‚‚Oв‚‚","HO","Hв‚‚O","HOв‚‚"]', 'HO', 'easy', 2, 'both', 'Dividing Hв‚‚Oв‚‚ subscripts by 2 gives HO.', 'chem', 'ch01', 'ch01t3', 'ch01t3s2'),
('axai_ch01_177', 'If the molar mass of a compound is 80 and its empirical formula mass is 40, the value of n is:', 'mcq', '["1","2","3","4"]', '2', 'easy', 1, 'both', 'n = molar mass Г· empirical formula mass = 80/40 = 2.', 'chem', 'ch01', 'ch01t3', 'ch01t3s2'),
('axai_ch01_178', 'The empirical formula of ethane Cв‚‚Hв‚† is:', 'mcq', '["CHв‚‚","CHв‚ѓ","Cв‚‚Hв‚†","CHв‚„"]', 'CHв‚ѓ', 'easy', 2, 'both', 'Dividing Cв‚‚Hв‚† subscripts by 2 gives CHв‚ѓ.', 'chem', 'ch01', 'ch01t3', 'ch01t3s2'),
